import tensorflow as tf
from flask import Flask, request, jsonify
import pandas as pd
from sklearn.model_selection import train_test_split
from tensorflow.keras.models import Sequential
from tensorflow.keras.layers import Conv2D, MaxPooling2D, Flatten, Dense
from tensorflow.keras.preprocessing.image import ImageDataGenerator

app = Flask(__name__)

# Load and preprocess data
def load_and_preprocess_data(file_path):
    df = pd.read_csv(file_path)
    # Assuming the CSV has columns 'image_path' and 'label'
    image_paths = df['image_path'].tolist()
    labels = df['label'].tolist()

    # ImageDataGenerator for augmentation and preprocessing
    datagen = ImageDataGenerator(rescale=1./255, validation_split=0.2)

    train_generator = datagen.flow_from_dataframe(
        dataframe=df,
        x_col='image_path',
        y_col='label',
        target_size=(64, 64),
        batch_size=32,
        class_mode='categorical',
        subset='training'
    )

    validation_generator = datagen.flow_from_dataframe(
        dataframe=df,
        x_col='image_path',
        y_col='label',
        target_size=(64, 64),
        batch_size=32,
        class_mode='categorical',
        subset='validation'
    )

    return train_generator, validation_generator

# Build the model
def build_model(num_classes):
    model = Sequential([
        Conv2D(32, (3, 3), activation='relu', input_shape=(64, 64, 3)),
        MaxPooling2D((2, 2)),
        Conv2D(64, (3, 3), activation='relu'),
        MaxPooling2D((2, 2)),
        Flatten(),
        Dense(128, activation='relu'),
        Dense(num_classes, activation='softmax')
    ])
    model.compile(optimizer='adam', loss='categorical_crossentropy', metrics=['accuracy'])
    return model

# Train the model
def train_model(model, train_generator, validation_generator):
    history = model.fit(
        train_generator,
        steps_per_epoch=train_generator.samples // train_generator.batch_size,
        epochs=10,
        validation_data=validation_generator,
        validation_steps=validation_generator.samples // validation_generator.batch_size
    )
    return model

# API endpoint to upload training data and train the model
@app.route('/train', methods=['POST'])
def train():
    file = request.files['file']
    if file:
        file_path = 'uploads/' + file.filename
        file.save(file_path)
        train_generator, validation_generator = load_and_preprocess_data(file_path)
        num_classes = len(train_generator.class_indices)
        model = build_model(num_classes)
        trained_model = train_model(model, train_generator, validation_generator)
        return jsonify({'message': 'Model training completed successfully!'})

